class SaperGraphicController{constructor(t){this.rootNode=document.querySelector(".game-play__board"),this.nodeHeader=this.rootNode.querySelector(".game-play__board-header"),this.nodeContent=this.rootNode.querySelector(".game-play__board-content"),this.nodeFooter=this.rootNode.querySelector(".game-play__board-footer"),this.timer=new saperTimer(this.rootNode.querySelector(".game-play__board-timer")),this.counterNode=this.rootNode.querySelector(".game-play__board-counter"),this.gameController=t}displayBoard(){this.nodeContent.innerHTML="",this.nodeFooter.innerHTML="",this.nodeContent.style.height=`${25*this.gameController.sizeY}px`,this.rootNode.style.width=`${25*this.gameController.sizeX}px`,this.gameController.boardMap.forEach(t=>t.forEach(t=>{this.nodeContent.appendChild(t.getNode())})),this.updateCounter(this.gameController.mines),this.timer.start()}displayEndGame(t){this.nodeFooter.innerHTML=t}updateCounter(t){this.counterNode.textContent=t}stop(){return this.timer.stop(),this.timer.getEndTime()}}class saperTimer{constructor(t){this.node=t,this.interval=null,this.timeStart=null,this.timeEnd=null}start(){this.reset(),this.timeStart=Date.now(),this.interval=setInterval(()=>{this.timeEnd=Math.floor((Date.now()-this.timeStart)/1e3),this.refresh()},1e3)}stop(){clearInterval(this.interval)}reset(){this.stop(),this.timeEnd=0,this.refresh()}refresh(){this.node.textContent=this.timeEnd}getEndTime(){return this.timeEnd}}